@@ -160,1 +167,1 @@
-            return valueOf(coeffs[0]);
+            return valueOf(clonedCoeffs[0]);
@@ -165,1 +172,1 @@
-                if (coeffs[i -1] == 0) {
+                if (clonedCoeffs[i -1] == 0) {
@@ -174,1 +181,1 @@
-                new PolynomialDouble(Arrays.copyOf(coeffs, i));
+                new PolynomialDouble(Arrays.copyOf(clonedCoeffs, i));
@@ -282,2 +289,1 @@
